module testpf_72_tb;
    localparam   n = 72;
    localparam regs = 78;
    localparam  reg_bits = $clog2(regs);

    logic clk;
    logic rst;

    logic [10+28*n:0] word;
    logic [7:0] PC;
    logic [7:0] nextPC;
    wire [8*regs-1:0] reg_state;

    wire [(10+28*n)*14-1:0] prog;
    assign prog = {
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027',
2027'
    };
    

    processor #(.N(n), .Regs(regs)) dut (
                  .CLK(clk),
                  .rst(rst),
                  .word(word),
                  .PC(PC),
                  .nextPC(nextPC),
                  .reg_state(reg_state)
              );

    integer i;
    task dump();
        $write("  registers: \n");
        for (int i = 0; i < regs; i++) begin
            $write("    r%0d=%0d ", i, reg_state[8*i +: 8]);
        end
        $write("\n");
    endtask; // dump
    task fail(input logic [8*regs-1:0] arr, pc);
        $display("[ ERR] Failure in processor test case at #%0d", $time);
        $display("  pc real %d expected %d", nextPC, pc);
        $write("  expected: ");
        for (int i = 0; i < regs; i++) begin
            $write("%0d=%0d ", i, arr[8*i +: 8]);
        end
        $write("\n");
        dump();
        $finish;
    endtask
    task assert_correct(input logic [8*regs-1:0] arr, pc);
        for (int i=0; i<regs; i++) begin
            assert (arr[8*i +: 8] == reg_state[8*i +: 8]) else fail(arr, pc);
        end
        assert (pc == nextPC) else fail(arr, pc);
    endtask
    initial begin
        clk = 1'b0;
        forever begin
            #4 clk = 0;
            #6 clk = 1;
        end
    end

    // test cases
    initial
    begin

        $display("[INFO] Testing processor test1");
        rst <= 1;
        PC <= 0;
        word = '0;
        @(posedge clk);
        #0.7
        assert_correct('0, 0);
        rst <= 0;

        while (nextPC != 14) begin
          PC = nextPC;
          word = prog[2027*PC +: 2027];
          @(posedge clk);
          #3;
        end

        dump();
        $display("[PASS] Completed test1 test at %0d",$time);
        $finish;
    end
endmodule

